data.output:
	p := filepath.ToSlash(path)
	if !strings.HasPrefix(p, root) {
		return false
	}
	rest := p[len(root):]
	slash := strings.IndexByte(rest, '/')
	if slash < 0 {
		return false
	}
	dir := rest[:slash]
	if dir == phase {
		return true
	}
	// numeric prefix match: phase="01" matches dir="01-frame"
	if dash := strings.IndexByte(dir, '-'); dash > 0 && dir[:dash] == phase {
		return true
	}
	return false
}

// idPrefixSegment extracts the leading prefix segment from an artifact ID.
// IDs are typically formatted as "doc:<PREFIX>-..." (e.g. "doc:ADR-001-foo")
// or "<PREFIX>-..." for sidecar artifacts. The "doc:" / "sidecar:" namespace
// prefix, if present, is stripped before extraction. Returns empty string
// when no prefix segment can be identified.
func idPrefixSegment(id string) string {
	s := id
	for _, ns := range []string{"doc:", "sidecar:"} {
		if strings.HasPrefix(s, ns) {
			s = s[len(ns):]
			break
		}
	}
	if i := strings.IndexByte(s, '-'); i > 0 {
		return strings.ToUpper(s[:i])
	}
	return ""
}

// matchArtifactForSearch implements the TD-029 search precedence:
//
//  1. title
//  2. path
//  3. description
//  4. ddxFrontmatter (raw JSON)
//  5. body text (only when the file is text and within the size cap)
//
// The first matching field wins; later fields are not consulted. Returns
// the snippet (with the match marked) and whether the artifact matched.
// qLower must already be lowercased by the caller.
func matchArtifactForSearch(a *Artifact, root, qLower string) (string, bool) {
	if qLower == "" {
		return "", false
	}
	if hit, ok := substringSnippet(a.Title, qLower); ok {
		return hit, true
	}
	if hit, ok := substringSnippet(a.Path, qLower); ok {
		return hit, true
	}
	if a.Description != nil {
		if hit, ok := substringSnippet(*a.Description, qLower); ok {
			return hit, true
		}
	}
	if a.DdxFrontmatter != nil {
		if hit, ok := substringSnippet(*a.DdxFrontmatter, qLower); ok {
			return hit, true
		}
	}
	// Body search — bounded by size cap and binary skip.
	if shouldSearchBody(a.Path) {
		body, ok := readBodyForSearch(filepath.Join(root, filepath.FromSlash(a.Path)))
		if ok {
			if hit, ok := substringSnippet(body, qLower); ok {
				return hit, true
			}
		}
	}
	return "", false
}

// substringSnippet finds the (case-insensitive) first occurrence of qLower
// in text and returns a windowed snippet around it with the match wrapped
// in "**…**" markers. Reports false when no match is found.
func substringSnippet(text, qLower string) (string, bool) {
	if text == "" || qLower == "" {
		return "", false
	}
	lower := strings.ToLower(text)
	idx := strings.Index(lower, qLower)
	if idx < 0 {
		return "", false
	}
	matchLen := len(qLower)
	// Compute window in rune-aware-ish bounds; falling back to bytes is
	// safe for the predominantly-ASCII content we search, and the marker
	// preserves the original casing of the matched substring.
	start := idx - snippetWindowChars
	if start < 0 {
		start = 0
	}
	end := idx + matchLen + snippetWindowChars
	if end > len(text) {
		end = len(text)
	}
	var b strings.Builder
	if start > 0 {
		b.WriteString("…")
	}
	b.WriteString(text[start:idx])
	b.WriteString("**")
	b.WriteString(text[idx : idx+matchLen])
	b.WriteString("**")
	b.WriteString(text[idx+matchLen : end])
	if end < len(text) {
		b.WriteString("…")
	}
	return b.String(), true
}

// shouldSearchBody reports whether a file at the given relative path is
// eligible for body content search. Binary file extensions are skipped per
// the TD-029 allowlist. SVG and Excalidraw JSON are explicitly text.
func shouldSearchBody(relPath string) bool {
	lower := strings.ToLower(relPath)
	// Excalidraw JSON variants are text.
	if strings.HasSuffix(lower, ".excalidraw") || strings.HasSuffix(lower, ".excalidraw.json") {
		return true
	}
	// .excalidraw.png is binary (covered by .png extension below).
	ext := filepath.Ext(lower)
	if ext == "" {
		return true
	}
	if _, isBinary := binarySearchExtensions[ext]; isBinary {
		return false
	}
	return true
}

// readBodyForSearch reads up to searchBodySizeCapBytes from absPath. Files
// whose first 512 bytes contain a NUL byte are classified as binary and
// skipped. Returns the trimmed content and whether it should be searched.
func readBodyForSearch(absPath string) (string, bool) {
	f, err := os.Open(absPath)
	if err != nil {
		return "", false
	}
	defer f.Close()
	buf := make([]byte, searchBodySizeCapBytes)
	n, err := io.ReadFull(f, buf)
	if err != nil && err != io.ErrUnexpectedEOF && err != io.EOF {
		return "", false
	}
	if n == 0 {
		return "", false
	}
	data := buf[:n]
	// Binary content sniff: NUL byte in the first 512 bytes signals binary.
	sniffEnd := 512
	if len(data) < sniffEnd {
		sniffEnd = len(data)
	}
	for i := 0; i < sniffEnd; i++ {
		if data[i] == 0 {
			return "", false
		}
	}
	return string(data), true
}

package graphql

import (
	"context"
	"crypto/sha256"
	"encoding/hex"
	"fmt"
	"math/rand"
	"os"
	"path/filepath"
	"sort"
	"testing"
	"time"
)

// BenchmarkArtifactsSearch_500Fixture builds the 500-artifact fixture defined
// in TD-029 (Artifact Full-Text Search & Facet Contract) and measures the p95
// latency of a `q` substring query against it.
//
// The fixture composition mirrors the TD-029 "Performance budget" table:
// 200 small md, 100 medium md, 50 large md, 25 oversize md, 75 PNG, 50 tar.
// Binary-classed files (PNG, tar) carry .ddx.yaml sidecars marked with the
// matching media types so collectSidecarArtifacts records them.
//
// This bead (Story 6 B4a) lands the benchmark harness only. Resolver-level
// body search is added in B4b; until then this benchmark measures the
// title∪path baseline against the same fixture so B4b regressions are
// visible against an apples-to-apples baseline.
func BenchmarkArtifactsSearch_500Fixture(b *testing.B) {
	root := buildBench500Fixture(b)
	r := &Resolver{WorkingDir: root}
	qr := &queryResolver{r}
	ctx := context.Background()

	// "ipsum" is sprinkled across textual fixture bodies and titles
	// (see writeMarkdownFixture) so the search produces non-zero hits.
	q := "ipsum"

	// Warm fs cache and verify the resolver returns matches before we
	// start timing — a cold first call dominates p95 otherwise and a
	// silent zero-match search would make the benchmark meaningless.
	if conn, err := qr.Artifacts(ctx, "bench", nil, nil, nil, nil, nil, &q, nil, nil, nil, nil); err != nil {
		b.Fatalf("warmup: %v", err)
	} else if conn.TotalCount == 0 {
		b.Fatalf("warmup: expected matches for %q, got 0", q)
	}

	durations := make([]time.Duration, 0, b.N)
	b.ResetTimer()
	for i := 0; i < b.N; i++ {
		start := time.Now()
		_, err := qr.Artifacts(ctx, "bench", nil, nil, nil, nil, nil, &q, nil, nil, nil, nil)
		d := time.Since(start)
		if err != nil {
			b.Fatalf("iter %d: %v", i, err)
		}
		durations = append(durations, d)
	}
	b.StopTimer()

	if len(durations) == 0 {
		return
	}
	sort.Slice(durations, func(i, j int) bool { return durations[i] < durations[j] })
	pct := func(p float64) time.Duration {
		idx := int(float64(len(durations)-1) * p)
		return durations[idx]
	}
	b.ReportMetric(float64(pct(0.50).Microseconds()), "p50_us/op")
	b.ReportMetric(float64(pct(0.95).Microseconds()), "p95_us/op")
	b.ReportMetric(float64(pct(0.99).Microseconds()), "p99_us/op")
}

// buildBench500Fixture writes 500 artifacts under <tmp>/.ddx/plugins/ and
// returns the project root. The directory is cleaned up by testing.B.
func buildBench500Fixture(tb testing.TB) string {
	tb.Helper()
	root := tb.TempDir()
	pluginDir := filepath.Join(root, ".ddx", "plugins", "bench")
	if err := os.MkdirAll(pluginDir, 0o755); err != nil {
		tb.Fatal(err)
	}

	rng := rand.New(rand.NewSource(1)) // deterministic fixture

	type spec struct {
		count     int
		minBytes  int
		maxBytes  int
		mediaType string
		ext       string
		writer    func(path string, size int, rng *rand.Rand) error
	}
	specs := []spec{
		{200, 1 << 10, 8 << 10, "text/markdown", ".md", writeMarkdownFixture},
		{100, 8 << 10, 64 << 10, "text/markdown", ".md", writeMarkdownFixture},
		{50, 64 << 10, 256 << 10, "text/markdown", ".md", writeMarkdownFixture},
		{25, 1 << 20, 4 << 20, "text/markdown", ".md", writeMarkdownFixture},
		{75, 4 << 10, 32 << 10, "image/png", ".png", writeBinaryFixture},
		{50, 32 << 10, 256 << 10, "application/x-tar", ".tar", writeBinaryFixture},
	}

	idx := 0
	for si, s := range specs {
		for i := 0; i < s.count; i++ {
			idx++
			size := s.minBytes
			if s.maxBytes > s.minBytes {
				size += rng.Intn(s.maxBytes - s.minBytes)
			}
			name := fmt.Sprintf("artifact-%03d-%d-%d%s", idx, si, i, s.ext)
			artifactPath := filepath.Join(pluginDir, name)
			if err := s.writer(artifactPath, size, rng); err != nil {
				tb.Fatal(err)
			}
			// Compute hash so generated_by.source_hash matches → "fresh".
			data, err := os.ReadFile(artifactPath)
			if err != nil {
				tb.Fatal(err)
			}
			h := sha256.Sum256(data)
			sidecar := fmt.Sprintf(`ddx:
  id: BENCH-%04d
  title: "Artifact ipsum %d (%s)"
  media_type: %s
  description: "Lorem ipsum dolor sit amet, sample artifact %d for the bench fixture."
  generated_by:
    run_id: bench-run
    prompt_summary: "bench fixture"
    source_hash: %s
`, idx, idx, s.mediaType, s.mediaType, idx, hex.EncodeToString(h[:]))
			if err := os.WriteFile(artifactPath+".ddx.yaml", []byte(sidecar), 0o644); err != nil {
				tb.Fatal(err)
			}
		}
	}
	return root
}

// writeMarkdownFixture writes a deterministic markdown file of approximately
// `size` bytes with embedded "ipsum" tokens that the q="ipsum" search hits.
func writeMarkdownFixture(path string, size int, rng *rand.Rand) error {
	const para = "Lorem ipsum dolor sit amet, consectetur adipiscing elit. " +
		"Sed do eiusmod tempor incididunt ut labore et dolore magna aliqua. " +
		"Ut enim ad minim veniam, quis nostrud exercitation ullamco laboris. "
	f, err := os.Create(path)
	if err != nil {
		return err
	}
	defer f.Close()
	if _, err := fmt.Fprintf(f, "# Bench Artifact (ipsum %d)\n\n", rng.Int()); err != nil {
		return err
	}
	written := 0
	for written < size {
		n, err := f.WriteString(para)
		if err != nil {
			return err
		}
		written += n
	}
	return nil
}

// writeBinaryFixture writes a deterministic pseudo-binary blob with NUL bytes
// scattered through it so a content-sniff classifier flags it as binary.
func writeBinaryFixture(path string, size int, rng *rand.Rand) error {
	buf := make([]byte, size)
	if _, err := rng.Read(buf); err != nil {
		return err
	}
	// Inject NULs at regular intervals to make the binary-sniff
	// rule (NUL byte in first 512 bytes) trigger reliably.
	for i := 0; i < len(buf); i += 64 {
		buf[i] = 0
	}
	return os.WriteFile(path, buf, 0o644)
}
